113	// loadProviderModels returns a fresh result, performing a live discovery only
114	// when no other goroutine is already doing so. When an in-flight fetch exists
115	// for this key, the caller waits on its completion and then reads the cache.
116	func loadProviderModels(ctx context.Context, workDir, name string, kind ProviderKind, key string) (*ProviderModelsResult, error) {
117		return doProviderModelsFetch(ctx, workDir, name, kind, key, false)
118	}
119	
120	// refreshProviderModels forces a live discovery (no TTL check), still
121	// coalescing concurrent calls for the same key.
122	func refreshProviderModels(ctx context.Context, workDir, name string, kind ProviderKind, key string) (*ProviderModelsResult, error) {
123		return doProviderModelsFetch(ctx, workDir, name, kind, key, true)
124	}
125	
126	func doProviderModelsFetch(ctx context.Context, workDir, name string, kind ProviderKind, key string, force bool) (*ProviderModelsResult, error) {
127		for {
128			providerModelsCache.Lock()
129			// If a fetch is in flight for this key, wait for it and re-evaluate.
130			if ch, ok := providerModelsCache.inFlight[key]; ok {
131				providerModelsCache.Unlock()
132				select {
133				case <-ch:
134					if !force {
135						if entry, ok := lookupProviderModelsCache(key); ok {
136							return entry.result, nil
137						}
138					}
139					// Fall through to retry — we either need a fresh fetch or the
140					// previous attempt failed.
141					continue
142				case <-ctx.Done():
143					return nil, ctx.Err()
144				}
145			}
146			// We own the in-flight slot.
147			ch := make(chan struct{})
148			providerModelsCache.inFlight[key] = ch
149			providerModelsCache.Unlock()
150	
151			result, err := providerModelsFetcher(ctx, workDir, name, kind)
152	
153			providerModelsCache.Lock()
154			delete(providerModelsCache.inFlight, key)
155			if err == nil && result != nil {
156				providerModelsCache.entries[key] = providerModelsCacheEntry{
157					result:    result,
158					fetchedAt: time.Now().UTC(),
159				}
160			}
161			providerModelsCache.Unlock()
162			close(ch)
163	
164			if err != nil {
165				return nil, err
166			}
167			return result, nil
168		}
169	}
